@graph.node
def assemble_context(state: RAGState):
    # Deduplicate and sort by relevance
    unique_docs = []
    seen_hashes = set()

    for doc, score in zip(state['documents'], state['relevance_scores']):
        doc_hash = hash(doc['content'][:100])
        if doc_hash not in seen_hashes:
            unique_docs.append((doc, score))
            seen_hashes.add(doc_hash)

    unique_docs.sort(key=lambda x: x[1], reverse=True)
    context = "\n".join([doc[0]['content'] for doc in unique_docs[:3]])

    return {
        'context': context,
        'citations': [doc[0]['source'] for doc in unique_docs[:3]]
    }

