import vex

# Initialize Vex client
vex_client = vex.Client(api_key="your-vex-api-key")

# Define verification policy
policy = {
    "name": "rag-faithfulness",
    "verifications": [
        "source_faithfulness",
        "hallucination_detection",
        "citation_accuracy"
    ],
    "risk_profile": "high"
}

# Wrap graph execution
with vex_client.verify(policy=policy) as verifier:
    result = rag_graph.invoke({
        'query': user_query,
        'messages': []
    })

    # Submit for verification
    verdict = verifier.submit({
        'input': user_query,
        'output': result['response'],
        'context': result['context'],
        'citations': result['citations'],
        'sources': result['documents']
    })

    if verdict.passed:
        return result
    else:
        return handle_verification_failure(verdict)

@graph.node
def vex_verify(state: RAGState):
    response = vex_client.verify_sync(
        policy="rag-faithfulness",
        input=state['query'],
        output=state['response'],
        context=state['context'],
        citations=state['citations'],
        sources=[doc['content'] for doc in state['documents']]
    )

    if response['passed']:
        return state
    else:
        # Route to human review or fallback
        return {'needs_review': True, 'vex_report': response['issues']}

workflow.add_node('vex_verify', vex_verify)
workflow.add_conditional_edges(
    'synthesize',
    lambda state: 'vex_verify' if state.get('response') else END
)
workflow.add_edge('vex_verify', 'human_review' if needs_review else END)

from vex.cycle_detector import GraphCycleMonitor

cycle_monitor = GraphCycleMonitor(
    max_iterations=10,
    state_keys=['documents', 'context'],
    vex_client=vex_client
)

@cycle_monitor.wrap
def safe_graph_invoke(inputs):
    config = {"configurable": {"thread_id": "rag-session-1"}}
    return rag_graph.invoke(inputs, config)

# Usage with automatic cycle breaking
try:
    result = safe_graph_invoke({
        'query': user_query,
        'messages': []
    })
